const path = require('path');

const babelOptions = require('./babel-options');
const {
  getNonTranspiledModules,
  getTranspiledModules,
} = require('./module-paths');

// a space delimited list of strings (typically namespaces) to use in addition
// to "@folio" to determine if something needs Stripes-flavoured transpilation
const extraTranspile = process.env.STRIPES_TRANSPILE_TOKENS ? new RegExp(process.env.STRIPES_TRANSPILE_TOKENS.replaceAll(' ', '|')) : '';

// https://stackoverflow.com/questions/3446170/escape-string-for-use-in-javascript-regex/6969486#6969486
const escapeRegExp = string => string.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');

const bigTestRegex = /bigtest|interactor/i;
const nodeModulesRegex = /node_modules/;

module.exports = (modulePaths) => {
  const modulesToTranspile = getNonTranspiledModules(modulePaths);
  const transpiledModules = getTranspiledModules(modulePaths);
  let includeRegex;
  let excludeRegex;

  if (modulesToTranspile.length) {
    includeRegex = new RegExp(modulesToTranspile.map(escapeRegExp).join('|'));
    console.info('\nmodules to transpile:\n');
    modulesToTranspile.sort().forEach(m => console.log(m));
  }

  if (transpiledModules.length) {
    excludeRegex = new RegExp(transpiledModules.map(escapeRegExp).join('|'))
    console.info('\ntranspiled modules:\n');
    transpiledModules.forEach(m => console.log(m));
  }

  const folioModulePath = path.join('node_modules', '@folio');
  // A negative lookahead regex to find @folio modules present in node_modules
  // which are still not transpiled ('dist' folder is not present).
  // This currently happens when folio module is not listed in stripes config
  // or under stripes.stripesDeps and another folio module includes it as a dependency.
  // TODO: remove this after all modules are transpiled
  const folioModulesRegex = new RegExp(`${escapeRegExp(folioModulePath)}(?!.*dist)`);

  const shouldModuleBeIncluded = (modulePath) => {
    // exclude empty modules
    if (!modulePath) {
      return false;
    }

    // regex which represents modules which should be included for transpilation
    if (includeRegex && includeRegex.test(modulePath)) {
      return true;
    }

    // include STRIPES_TRANSPILE_TOKENS in transpilation
    if (extraTranspile && extraTranspile.test(modulePath)) {
      return true;
    }

    // regex which represents modules which should be excluded from transpilation
    if (excludeRegex && excludeRegex.test(modulePath)) {
      return false;
    }

    // if untranspiled @folio module is present in node_modules
    // just transpile it
    if (folioModulesRegex.test(modulePath)) {
      return true;
    }

    // skip everything from node_modules
    if (nodeModulesRegex.test(modulePath)) {
      return false;
    }

    return true;
  }

  return {
    test: /\.js$/,
    include: shouldModuleBeIncluded,
    oneOf: [
      {
        // handle all bigtest files and interactor files via babel
        // due to a decorator format issue.
        // https://issues.folio.org/browse/STRWEB-78
        test: filePath => !filePath.match(bigTestRegex),
        use: [
          {
            loader: 'esbuild-loader',
            options: {
              loader: 'tsx',
              jsx: 'automatic',
            },
          },
        ],
      },
      {
        use: [
          {
            loader: 'babel-loader',
            options: {
              cacheDirectory: true,
              ...babelOptions,
            },
          },
        ],
      },
   ],
  };
};

const utils = require('./utils');

module.exports = {
  presets: [
    ['@babel/preset-env', { targets: '> 0.25%, not dead' }],
    ['@babel/preset-flow', { all: true }],
    ['@babel/preset-react', {
      "runtime": "automatic"
    }],
    ['@babel/preset-typescript'],
  ],
  plugins: [
    ['@babel/plugin-proposal-decorators', { 'legacy': true }],
    // when building a platform directly, i.e. outside a workspace,
    // babel complains loudly and repeatedly that when these modules are enabled:
    // * @babel/plugin-proposal-class-properties,
    // * @babel/plugin-proposal-private-methods and
    // * @babel/plugin-proposal-private-property-in-object
    // the "loose" option must be the same for all three.
    // but @babel/preset-env sets it to false for ...private-methods.
    // overriding it here silences the complaint. STRWEB-12
    ['@babel/plugin-transform-class-properties', { 'loose': true }],
    ['@babel/plugin-transform-private-methods', { 'loose': true }],
    ['@babel/plugin-transform-private-property-in-object', { 'loose': true }],
    '@babel/plugin-transform-export-namespace-from',
    '@babel/plugin-proposal-function-sent',
    '@babel/plugin-transform-numeric-separator',
    '@babel/plugin-proposal-throw-expressions',
    '@babel/plugin-syntax-import-meta',
    utils.isDevelopment && require.resolve('react-refresh/babel'),

  ].filter(Boolean),
};

const isDevelopment = process.env.NODE_ENV === 'development';
const isProduction = process.env.NODE_ENV === 'production';

// processExternals
// Accepts a list of peerDeps in the shape of an object
// with  { [packageName]: [version] }
// this generates configuration for setting the peer dep as
// an 'external' dependency for webpack, meaning it won't be bundled,
// but will be expected to exist where the bundle is executed.
// the different module types adjust the way webpack transforms the code when
// an external module is encountered within a particular module.
const processExternals = (peerDeps) => {
  return Object.keys(peerDeps).reduce((acc, name) => {
    acc[name] = {
      root: name,
      commonjs2: name,
      commonjs: name,
      amd: name,
      umd: name
    };

    return acc;
  }, {});
};

// processShared
// This function takes an object of shared dependencies in the shape of
// { [packageName]: [version] } ex { '@folio/stripes': '^9.3.0' }
// and applies additional options for the module federation configuration,
// like setting the shared items as singletons, or using the 'eager' consumption
// setting (chunks are included in the initial bundle whether than split out/lazy loaded)
const processShared = (shared, options = {}) => {
  return Object.keys(shared).reduce((acc, name) => {
    acc[name] = {
      requiredVersion: shared[name],
      ...options
    };

    return acc;
  }, {});
};

module.exports = {
  processExternals,
  isDevelopment,
  isProduction,
  processShared,
};

const path = require('path');
const logger = require('./logger')();
const StripesBuildError = require('./stripes-build-error');

function tryResolve(modulePath, options) {
  try {
    return require.resolve(modulePath, options);
  } catch (e) {
    return false;
  }
}

// Generates a resolvable alias for a module with preference given to the
// workspace's version followed by stripes-core's version followed by the platform's, if available
function generateStripesAlias(moduleName) {
  let alias;
  const workspaceModule = path.join(path.resolve(), '..', 'node_modules', moduleName);
  const platformModule = path.join(path.resolve(), 'node_modules', moduleName);
  const coreModule = path.join(__dirname, '..', 'node_modules', moduleName);

  if (tryResolve(workspaceModule)) {
    alias = workspaceModule;
  } else if (tryResolve(platformModule)) {
    alias = platformModule;
  } else if (tryResolve(coreModule)) {
    alias = coreModule;
  } else {
    throw new StripesBuildError(`generateStripesAlias: Unable to locate a resolvable alias for ${moduleName} module`);
  }
  return alias;
}

// Common logic to locate a stripes module (pass 'package.json') or file within
function locateStripesModule(context, moduleName, alias, ...segments) {
  logger.log(`locating stripes module ${moduleName}...`);
  let foundPath = false;

  const tryPaths = [
    {
      // The place we normally expect to find this module
      request: path.join(context, 'node_modules', moduleName, ...segments),
    }, {
      // The above resolution is overspecific and prevents some use cases eg. yarn workspaces
      request: path.join(moduleName, ...segments),
    }, {
      // This better incorporates the context path but requires nodejs 9+
      request: path.join(moduleName, ...segments),
      options: { paths: [context] },
    }, {
      // Yarn workspaces fallback: Try node_modules of the parent directory
      request: path.join(context, '..', 'node_modules', moduleName, ...segments),
    },
  ];

  // If we are looking for any stripes-* modules, we should also check within the framework's node_modules
  if (moduleName.startsWith('@folio/stripes')) {
    tryPaths.unshift({
      request: path.join(context, 'node_modules', '@folio', 'stripes', 'node_modules', moduleName, ...segments),
    }, {
      // Yarn workspace fallback
      request: path.join(context, '..', 'node_modules', '@folio', 'stripes', 'node_modules', moduleName, ...segments),
    });
  }

  // When available, try for the alias first
  if (alias && alias[moduleName]) {
    tryPaths.unshift({
      request: path.join(alias[moduleName], ...segments),
    });
  }

  for (let i = 0; i < tryPaths.length; i += 1) {
    foundPath = tryResolve(tryPaths[i].request, tryPaths[i].options);
    if (foundPath) {
      break;
    }
  }
  if (foundPath) {
    logger.log('found', foundPath);
  }
  return foundPath;
}

/**
 * Returns a full path of package.json for a given module.
 */
function locatePackageJsonPath(moduleName) {
  const packageJsonPath = locateStripesModule(process.cwd(), moduleName, {}, 'package.json');

  // Also check package.json in the current cwd dir.
  // This handles a case when `stripes serve` is executed for a single ui module (within the module).
  if (!packageJsonPath) {
    const localPath = tryResolve(path.join(process.cwd(), 'package.json'));

    if (localPath) {
      const packageJson = require(localPath);
      // make sure it's the same package name as depName
      if (packageJson.name === moduleName) {
        return localPath;
      }
    }
  }

  return packageJsonPath;
}

/**
 * Convert dependencies defined in "stripes.stripesDeps" in package.json
 * into their full path representation.
 *
 * For example dependencies defined as:
 *
 * "stripesDeps": [
    "@reshare/stripes-reshare",
  ],
 *
 * will be converted to:
 *
 * [
 *  './node_modules/@reshare/stripes-reshare'
 * ]
 *
*/
function getStripesDepsPaths(packageJsonPath) {
  const packageJson = require(packageJsonPath);
  const stripes = packageJson.stripes || {};

  if (!stripes.stripesDeps) {
    return null;
  }

  const stripesDeps = stripes.stripesDeps;

  return stripesDeps.map(dep => {
    const packageJsonPath = locatePackageJsonPath(dep);
    return packageJsonPath ? path.dirname(packageJsonPath) : null;
  });
}

/**
 * Convert modules defined in stripes config into their full path representation.
 * The conversion will happen for all modules found in stripes config.
 *
 * For example modules defined in stripes config:
 *
 * modules: { '@folio/users': {}, '@reshare/directory': {} }
 *
 * will be converted to:
 *
 * [
 *  './node_modules/@folio/users',
 *  './node_modules/@reshare/directory'
 * ]
 *
 *
*/
function getModulesPaths(modules) {
  return Object
    .keys(modules)
    .flatMap(module => {
      const packageJsonPath = locatePackageJsonPath(module);

      if (packageJsonPath) {
        const modulePaths = [path.dirname(packageJsonPath)];
        const stripesDepPaths = getStripesDepsPaths(packageJsonPath);

        if (stripesDepPaths) {
          modulePaths.push(...stripesDepPaths);
        }

        return modulePaths
      }

      return null;
    })
    .filter(module => !!module);
}

/**
 * Return full paths for all stripes dependencies defined in:
 *
 * https://github.com/folio-org/stripes/blob/ab01ed9c8d60d020d76f5682406b3bf901c24e76/package.json#L20-L27
 *
*/
function getStripesModulesPaths() {
  const packageJsonPath = locatePackageJsonPath('@folio/stripes');
  const paths = [];

  if (!packageJsonPath) {
    return paths;
  }

  const packageJson = require(packageJsonPath);

  if (!packageJson) {
    return paths;
  }

  Object.keys(packageJson.dependencies).forEach(moduleName => {
    if (moduleName.match('@folio')) {
      const stripesModulePath = locatePackageJsonPath(moduleName);

      if (stripesModulePath) {
        paths.push(path.dirname(stripesModulePath));
      }
    }
  });

  return paths;
}

function getNonTranspiledModules(modules) {
  const nonTranspiledModules = ['stripes-config'];

  modules.forEach(module => {
    const distPath = tryResolve(path.join(module, 'dist'));
    if (!distPath) {
      nonTranspiledModules.push(module.split(path.sep).pop());
    }
  });

  return [...new Set(nonTranspiledModules)];
}

function getTranspiledModules(modules) {
  const transpiledModules = [];

  modules.forEach(module => {
    const distPath = tryResolve(path.join(module, 'dist'));

    if (distPath) {
      transpiledModules.push(distPath);
    }
  });

  return transpiledModules;
}

function getTranspiledCssPaths(modules) {
  const cssPaths = [];

  modules.forEach(module => {
    const cssPath = tryResolve(path.join(module, 'dist', 'style.css'));

    if (cssPath) {
      cssPaths.push(cssPath);
    }
  });

  return cssPaths;
}

function getSharedStyles(filename) {
  return path.resolve(generateStripesAlias('@folio/stripes-components'), `${filename}.css`);
}

module.exports = {
  tryResolve,
  generateStripesAlias,
  getSharedStyles,
  locateStripesModule,
  getModulesPaths,
  getStripesModulesPaths,
  getNonTranspiledModules,
  getTranspiledModules,
  getTranspiledCssPaths,
  locatePackageJsonPath,
};

const debug = require('debug');

// Wrapper for debug to ensure consistent use of namespace
module.exports = function getLogger(name) {
  const namespace = name ? `stripes-core:${name}` : 'stripes-core';
  const logger = debug(namespace);

  return {
    log: (...args) => logger(...args),
  };
};

module.exports = class StripesBuildError extends Error {
  constructor(...args) {
    super(...args);
    this.name = this.constructor.name;
    Error.captureStackTrace(this, StripesBuildError);
  }
};

// Anything that we want *the platform to provide to modules should be here.
// If an item is not in this list, modules will each load their own version of it.
// This can be problematic for React Context if multiple copies of the same context are loaded.

// This list is best thought of as 'aliases' vs package-names. Whether or not the host
// app provides the dependency depends on exactly *how the remote app imports it.
// ex:
//    ✓ import { Route } from 'react-router'   // covered by this list
//    ✗ import Route from 'react-router/route' // not covered
// deep imports should be marked with their offending app for future pruning of this list.
// ui-modules should not have deep imports unless they absolutely have to.
const singletons = {
  '@folio/stripes-components': '^13.1.0',
  '@folio/stripes-connect': '^10.0.1',
  '@folio/stripes-core': '^11.1.0',
  "moment": "^2.29.0",
  'react': '~18.3',
  'react-dom': '~18.3',
  'react-intl': '^7.1.14',
  'react-query': '^3.39.3',
  'react-redux': '^8.1',
  'react-router': '^5.2.0',
  'react-router-dom': '^5.2.0',
  'redux-observable': '^1.2.0',
  'rxjs': '^6.6.3',
  'rxjs/operators': '^6.6.3', // for eholdings usage
};

/**
 * getHostAppSingletons
 * get singletons from stripes-core package.json on Github.
 */
const getHostAppSingletons = () => {
  let platformSingletons = {};

  const handlePkgData = (corePkg) => {
    const pkgObject = corePkg.data ? JSON.parse(corePkg.data) : corePkg;
    const stripesCoreVersion = pkgObject.version;
    platformSingletons['@folio/stripes-core'] = `~${stripesCoreVersion}`;
    Object.keys(singletons).forEach(dep => {
      const depVersion = pkgObject.peerDependencies[dep];
      if (depVersion) {
        platformSingletons[dep] = depVersion;
      }
    });
    platformSingletons = { ...platformSingletons, ...singletons };
  }

  let corePkg;
  // try to get the locally installed stripes-core
  try {
    corePkg = require('@folio/stripes-core/package.json');
  } catch (e) {
    corePkg = singletons;
    throw new Error('Error retrieving singletons list from platform. Falling back to static list');
  }

  handlePkgData(corePkg);
  return platformSingletons;
}

const defaultDiscoveryUrl = 'http://localhost:3001/registry';

const HOST_RUNTIME_PLUGIN_NAME = 'stripes-injected-mf-runtime-plugin';

module.exports = {
  defaultDiscoveryUrl,
  singletons,
  getHostAppSingletons,
  HOST_RUNTIME_PLUGIN_NAME,
};

// This file can be used to attach lifecycle hooks to the module federation runtime logic.
// See https://module-federation.io/guide/runtime/runtime-hooks.html for possible entries.
import { HOST_RUNTIME_PLUGIN_NAME } from '../consts.js';

const StripesInjectedMFRuntimePlugin = () => ({
  name: HOST_RUNTIME_PLUGIN_NAME,
  // collect requests for shares that are different versions from the host app's provided versions for debugging purposes.
  // accessible in the console via the __DEBUG_MISSED_DEPS__ global variable.
  async beforeLoadShare(args) {
    if (!globalThis.__DEBUG_MISSED_DEPS__) {
      globalThis.__DEBUG_MISSED_DEPS__ = [];
    }

    // Only proceed if there is a host modfed instance, meaning modfed has initialized.
    // these can be viewed in the console with the __FEDERATION__.__INSTANCES__ global variable.
    const hostInstance = __FEDERATION__.__INSTANCES__[0];
    if (!hostInstance) {
      return args;
    }

    const { origin, shareInfo, pkgName } = args;

    // Only proceed if the host app provides a shared module of the same name.
    const hostShared = hostInstance.options.shared[pkgName][0];

    if (!hostShared) {
      return args;
    }

    let hostVersion = hostShared.version;

    // If the remote requires a different version of the shared module fom the host, add it to the __DEBUG_MISSED_DEPS__ global variable for debugging purposes.
    if (shareInfo.shareConfig.requiredVersion !== hostVersion) {
      if (globalThis.__DEBUG_MISSED_DEPS__.findIndex(s => s.pkgName === pkgName && s.remoteApp === origin.name) === -1) {
        globalThis.__DEBUG_MISSED_DEPS__.push({ pkgName, hostVersion: hostVersion, remoteApp: origin.name, ...shareInfo });
      }
    }

    return args;
  },
});

export default StripesInjectedMFRuntimePlugin;

// Remote containers include runtime plugins from their own build configuration, but not those of the host.
// In order for the remote's runtime plugins to be updated without a rebuild,
// we need to apply the host's plugins to the remote's container.
// This plugin sets a lifecycle method Before initialization of the remote's ModuleFederation instance
// to pass the host's runtime plugins to the remote container.
// The name of the plugin needs to match here, so we import it from a constant.
import { HOST_RUNTIME_PLUGIN_NAME } from "../consts.js";

const RemoteRuntimePlugin = () => ({
  name: 'remote-runtime-plugin',
  beforeInit(args) {

    // get override plugin from host instance...
    const hostInstance = __FEDERATION__.__INSTANCES__[0];
    if (!hostInstance) {
      return args;
    }
    const hostInjectedPlugin = hostInstance.options.plugins.find(plugin => plugin.name === HOST_RUNTIME_PLUGIN_NAME);
    if (!hostInjectedPlugin) {
      return args;
    }

    // injects it into new instance at runtime.
    const { origin } = args;
    origin.registerPlugins([hostInjectedPlugin]);

    return args;
  },
});

export default RemoteRuntimePlugin;

// These default branding values are used when no branding is present in stripes.config.js
// Default src are prefixed with '@folio/stripes-core' so they can be imported
// and processed through the webpack loaders from the stripes-core in use.
module.exports = {
  logo: {
    src: `${__dirname}/folio-logo.svg`,
    alt: 'FOLIO',
  },
  favicon: {
    src: `${__dirname}/favicon.svg`,
  },
};

// This webpack plugin generates a virtual module containing the stripes tenant branding configuration
// The virtual module contains require()'s needed for webpack to pull images into the bundle.

const path = require('path');
const FaviconsWebpackPlugin = require('favicons-webpack-plugin');
const defaultBranding = require('../default-assets/branding');
const logger = require('./logger')('stripesBrandingPlugin');
const StripesConfigPlugin = require('./stripes-config-plugin');

// Minimal favicon settings for favicons-webpack-plugin
const standardFaviconsOnly = {
  android: false,
  appleIcon: false,
  appleStartup: false,
  coast: false,
  favicons: true,
  firefox: false,
  windows: false,
  yandex: false,
};

// Complete favicon settings for favicons-webpack-plugin
const allFavicons = {
  android: true,
  appleIcon: true,
  appleStartup: true,
  coast: true,
  favicons: true,
  firefox: true,
  windows: true,
  yandex: true,
};

module.exports = class StripesBrandingPlugin {
  constructor(options) {
    logger.log('initializing...');
    // TODO: Validate incoming tenantBranding paths
    const tenantBranding = (options && options.tenantBranding) ? options.tenantBranding : {};
    this.branding = Object.assign({}, defaultBranding, tenantBranding);
    this.buildAllFavicons = options && options.buildAllFavicons;
  }

  apply(compiler) {
    // favicons-webpack-plugin will inject the necessary html via HtmlWebpackPlugin
    const faviconOptions = this._getFaviconOptions();
    new FaviconsWebpackPlugin(faviconOptions).apply(compiler);

    // Hook into stripesConfigPlugin to supply branding config
    StripesConfigPlugin.getPluginHooks(compiler).beforeWrite.tap('StripesTranslationsPlugin', (config) => {
      config.branding = this.branding;
      logger.log('stripesConfigPluginBeforeWrite', config.branding);
    });
  }

  _getFaviconOptions() {
    const faviconOptions = {
      logo: StripesBrandingPlugin._initFavicon(this.branding.favicon.src),
      icons: this.buildAllFavicons ? allFavicons : standardFaviconsOnly,
    };
    logger.log('favicon options', faviconOptions);
    return faviconOptions;
  }

  // Prep favicon path for use with HtmlWebpackPlugin
  static _initFavicon(favicon) {
    if (path.isAbsolute(favicon)) {
      return favicon;
    }
    return path.join(path.resolve(), favicon);
  }
};

// This webpack plugin generates a virtual module containing the stripes configuration
// To access this configuration simply import 'stripes-config' within your JavaScript:
//   import { okapi, config, modules } from 'stripes-config';
//
// NOTE: If importing module data for UI purposes such as displaying
// the module name, DO NOT import this module.
// Instead, use the ModulesContext directly or via the withModules/withModule HOCs.

const _ = require('lodash');
const VirtualModulesPlugin = require('webpack-virtual-modules');
const serialize = require('serialize-javascript');
const { SyncHook } = require('tapable');
const stripesModuleParser = require('./stripes-module-parser');
const StripesBuildError = require('./stripes-build-error');
const stripesSerialize = require('./stripes-serialize');
const logger = require('./logger')('stripesConfigPlugin');

const stripesConfigPluginHooksMap = new WeakMap();

module.exports = class StripesConfigPlugin {
  // options is actually stripes.config.js
  constructor(options, lazy) {
    logger.log('initializing...');
    if (!_.isObject(options.modules)) {
      throw new StripesBuildError('stripes-config-plugin was not provided a "modules" object for enabling stripes modules');
    }
    this.options = _.omit(options, 'branding', 'errorLogging');
    this.lazy = lazy;
  }

  // Establish hooks for other plugins to update the config, providing existing config as context
  static getPluginHooks = (compiler) => {
    let hooks = stripesConfigPluginHooksMap.get(compiler);

    if (!hooks) {
      hooks = {
        beforeWrite: new SyncHook(['config']),
      };

      stripesConfigPluginHooksMap.set(compiler, hooks);
    }

    return hooks;
  }

  apply(compiler) {
    const enabledModules = this.options.modules;
    logger.log('enabled modules:', enabledModules);
    const { config, metadata, icons, stripesDeps, warnings, lazyImports } = stripesModuleParser.parseAllModules(enabledModules, compiler.context, compiler.options.resolve.alias, this.lazy);
    const modulesInitialState = {
      app: [],
      handler: [],
      plugin: [],
      settings: [],
    };
    this.mergedConfig = Object.assign({ modules: modulesInitialState }, this.options, { modules: config });
    this.metadata = metadata;
    this.icons = icons;
    this.warnings = warnings;
    // Prep the virtual module now, we will write to it when ready
    this.virtualModule = new VirtualModulesPlugin();
    this.virtualModule.apply(compiler);

    StripesConfigPlugin.getPluginHooks(compiler).beforeWrite.tap(
      { name: 'StripesConfigPlugin', context: true },
      context => Object.assign(context, { config, metadata, icons, stripesDeps, warnings }));

    // Wait until after other plugins to generate virtual stripes-config
    compiler.hooks.afterPlugins.tap('StripesConfigPlugin', (theCompiler) => this.afterPlugins(theCompiler));
    compiler.hooks.emit.tapAsync('StripesConfigPlugin', (compilation, callback) => this.processWarnings(compilation, callback));
  }

  afterPlugins(compiler) {
    // Data provided by other stripes plugins via hooks
    const pluginData = {
      branding: {},
      errorLogging: {},
      translations: {},
    };

    StripesConfigPlugin.getPluginHooks(compiler).beforeWrite.call(pluginData);

